      '<div class="rc-img"><img src="' + CAR_IMGS[c.key] + '" alt="' + c.brand + '"></div>' +
      '<div class="rc-info">' +
      '<div class="rc-brand">' + c.brand + "</div>" +
      '<div class="rc-name">' + c.name + "</div>" +
      '<div class="rc-spec">' + c.spec + "</div>" +
      '<div class="rc-price">' + c.price + "</div>" +
