}

function addCr(key, brand, name, spec, price) {
  var list = document.getElementById("crList");
  if (list.querySelector('[data-key="' + key + '"]')) return;
  var empty = list.querySelector(".cr-empty-wrap");
  if (empty) empty.remove();
  list.insertAdjacentHTML("beforeend",
    '<div class="cr-item" data-key="' + key + '">' +
    '<div class="cr-item-img"><img src="' + CAR_IMGS[key] + '" alt="' + brand + '"></div>' +
    '<div class="cr-item-info">' +
    '<div class="cr-item-brand">' + brand + "</div>" +
    '<div class="cr-item-name">' + name + "</div>" +
    '<div class="cr-item-price">' + price + "</div>" +
    "</div></div>");
}
function resetCr() {
  document.getElementById("crList").innerHTML =
    '<div class="cr-empty-wrap"><div class="cr-empty-ico">🚗</div><div class="cr-empty-txt">AI 상담 후<br>관심 차량이 표시됩니다</div></div>';
}

function scroll() { var b = document.getElementById("chatBody"); b.scrollTop = b.scrollHeight; }
function now() { return new Date().toLocaleTimeString("ko-KR", {hour:"2-digit", minute:"2-digit"}); }
function wishBtn(btn) { var on = btn.textContent.indexOf("♥") !== -1; btn.textContent = on ? "♡ 찜하기" : "♥ 찜됨"; btn.style.color = on ? "" : "#e53e3e"; }

document.getElementById("popularGrid").innerHTML = ALL_CARS.map(function(c) {
  return '<div class="prod-card">' +
    '<div class="pc-img"><img src="' + CAR_IMGS[c.key] + '" alt="' + c.brand + '">' +
    '<span class="pc-tag ' + c.tagC + '">' + c.tag + "</span>" +
    '<div class="pc-btns">' +
    '<button class="pc-btn" onclick="event.stopPropagation();wishBtn(this)">♡ 찜하기</button>' +
    '<button class="pc-btn">🛒 담기</button>' +
    "</div></div>" +
    '<div class="pc-info"><div class="pc-brand">' + c.brand + "</div>" +
    '<div class="pc-name">' + c.name + "</div>" +
    '<div class="pc-spec">' + c.spec + "</div>" +
    '<div class="pc-price">' + c.price + "</div></div></div>";
}).join("");
</script>
</body>

